mapper.select:
select ai.id, ai.name, ai.introduction, ai.district_id, ai.district_name, ai.city_id, ai.city_name, ai.province_id, ai.province_name, ai.address_detail, ai.latitude, ai.longitude, ai.phone, ai.is_release, mr.min_rent from apartment_info ai left join ( select apartment_id, min(rent) min_rent from room_info where is_deleted = 0 group by apartment_id ) mr on ai.id = mr.apartment_id
ai.is_deleted = 0 and ai.is_release = 1
and ai.province_id = #{queryVo.provinceId}
and ai.city_id = #{queryVo.cityId}
and ai.district_id = #{queryVo.districtId}
order by ai.id desc
